"""
MKT Christ — Luke all 24 chapters
Output: data/commentary/mkt-christ/luke.json
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

DATA = {
  "1": {
    "46": '<p>A type: the Magnificat. Mary\'s song is shaped by Hannah\'s prayer (1 Sam 2:1-10) — Hannah as the type of the Spirit-filled woman through whom the Lord\'s anointed enters the world. But the Magnificat exceeds Hannah\'s song: where Hannah praised for her personal vindication, Mary praises for the eschatological reversal that the incarnation initiates for all the humble and hungry of Israel and the world. The type (Hannah/Samuel) points to the antitype (Mary/Jesus) not as mere parallel but as fulfillment: what Hannah\'s prayer anticipated (the exaltation of the humble, the strength of the LORD\'s anointed) is now the content of the incarnation itself.</p>',
    "68": '<p>A fulfillment: blessed be the Lord God of Israel, for he has visited and redeemed his people. Zechariah\'s Benedictus identifies the births of John and Jesus as the visitation (episkope) of YHWH that all the prophets promised. The OT motif of divine visitation (YHWH visiting his people in mercy or judgment) reaches its fulfillment in the incarnation: God personally visits his people not through a prophet or angel but in the person of his Son. The redemption (lytrosis, v.68; lytrosan, v.74) is the Exodus-liberation pattern now applied to redemption from enemies (political) and from sin (spiritual), with both dimensions present.</p>'
  },
  "2": {
    "11": '<p>A direct revelation: a Savior, who is Christ the Lord, has been born for you in the city of David. The angelic announcement at the shepherds concentrates Luke\'s Christology in a single sentence. The Savior born in David\'s city is the fulfillment of the Davidic covenant, the messianic hope, and the divine rescue promised throughout the OT. Luke\'s characteristic soter (Savior) title connects Jesus to the salvation history of Israel (YHWH as Israel\'s only savior, Isa 43:11) while the details of the manger, the shepherds, and the town of Bethlehem anchor the salvation in the most ordinary and humble circumstances — the divine Savior in a feeding trough.</p>',
    "32": '<p>A fulfillment: a light for revelation to the Gentiles and for glory to your people Israel. Simeon\'s Nunc Dimittis applies the Isaianic Servant vocation (Isa 49:6) to the infant Jesus: he is the Servant who is a light to the nations. Luke\'s Gospel will be the narrative of this dual fulfillment — the glory of Israel (through the Jewish mission) and the light to the Gentiles (through the Gentile mission that Acts continues). The infant who cannot yet speak is already identified as the one in whom the universal Servant mission will be embodied and accomplished.</p>'
  },
  "4": {
    "18": '<p>A direct revelation: the Spirit of the Lord is upon me, because he has anointed me to proclaim good news to the poor. The Nazareth synagogue scene is Luke\'s programmatic statement of the Christological mission. Jesus reads Isa 61:1-2 and declares today this scripture has been fulfilled in your hearing (v.21) — the most explicit self-identification with the Isaianic Servant in the Synoptic Gospels. Luke presents the Christ\'s mission as the Jubilee: release to captives (from sin and from evil powers), sight to the blind, freedom for the oppressed, the year of the Lord\'s favor. The entire Gospel is the unfolding of this Jubilee-mission.</p>',
    "43": '<p>A direct revelation: I must preach the good news of the kingdom of God to the other towns as well; for I was sent for this purpose. The dei (it is necessary) of v.43 is one of Luke\'s most important theological terms — divine necessity shapes the mission at every point. Jesus was sent (apestalen) — the mission is not self-chosen but given by the Father. The kingdom of God that Jesus preaches is the reign of God becoming present in his own person; to hear Jesus is to encounter the kingdom\'s arrival.</p>'
  },
  "7": {
    "22": '<p>A fulfillment: go and tell John what you have seen and heard — the blind receive their sight, the lame walk, lepers are cleansed, the deaf hear, the dead are raised, the poor have good news proclaimed. Jesus\'s answer to the imprisoned John is the definitive self-identification from Isaiah: the signs that he lists are precisely the signs that Isaiah promised when YHWH comes to save (Isa 35:5-6, 61:1). Christ\'s identity is proven not by Messianic title-claim but by Isaianic sign-fulfillment; the question is not what do you claim to be? but what do you see happening? The works are the revelation.</p>'
  },
  "9": {
    "51": '<p>A direct revelation: when the days drew near for him to be taken up, he set his face to go to Jerusalem. Luke\'s travel-narrative framing (9:51-19:44) presents the entire journey to Jerusalem as a deliberate movement toward the passion, resurrection, and ascension. Jesus does not drift toward Jerusalem; he sets his face (Isa 50:7, the Servant who sets his face like flint to face opposition). Every parable and teaching in the travel narrative is colored by this deliberate journey toward the cross. The Christological claim is implicit: the one who moves with this resolve toward his own death is the one who has freely accepted the Father\'s mission from eternity.</p>'
  },
  "15": {
    "20": '<p>A revelation of God: the father of the prodigal son runs, embraces, and restores without condition. The father in the parable is transparently the image of God — no other first-century Jewish father would run (an undignified act) to embrace a disgraced son before any apology had been given. The parable is Jesus\'s defense of his own practice (receiving sinners) by revealing the Father\'s character: God himself is the running father who hosts the party for the found son and pleads with the older brother. Every feature of the father\'s excess (running, robe, ring, sandals, feast, self-humiliation at the party\'s edge) is a portrait of divine grace preceding, enabling, and exceeding human repentance.</p>'
  },
  "19": {
    "10": '<p>A direct revelation: the Son of Man came to seek and to save the lost. Luke\'s mission-statement frames the Zacchaeus encounter as the paradigmatic instance of the Son of Man\'s seeking-saving mission. The three parables of Luke 15 and the Zacchaeus narrative are the lived theology of Luke 19:10: the lost sheep sought by the shepherd, the lost coin sought by the woman, the lost son welcomed by the father, and now the lost Zacchaeus sought-and-found by the Son of Man himself. The mission of Luke\'s Gospel is the living-out of this one sentence, fulfilled supremely in the cross (where the Son of Man gives himself to save the utterly lost).</p>'
  },
  "22": {
    "20": '<p>A fulfillment: this cup that is poured out for you is the new covenant in my blood. Luke\'s cup-word (with the new covenant language from Jer 31:31-34) is the most explicit Jeremianic citation in the passion narratives. The new covenant — written on the heart, bringing forgiveness of sins, creating universal knowledge of YHWH — is inaugurated in the cup of Jesus\'s blood. The Passover context connects the new covenant blood to the Exodus blood (the lamb\'s blood that protected from the destroying angel): Christ\'s blood is simultaneously the final Passover (ending the old covenant\'s provisional atonement) and the new covenant\'s ratifying sacrifice.</p>',
    "37": '<p>A fulfillment: this scripture must be fulfilled in me: And he was numbered with the transgressors. Jesus\'s citation of Isa 53:12 before his arrest is the clearest evidence in the Synoptics that Jesus explicitly understood his death as the fulfillment of the Servant\'s vicarious suffering. The verb dei (must be fulfilled) indicates divine necessity: the Servant\'s path of bearing sin for the many was not merely predictive of his death but constitutive of the divine plan from which the cross received its saving power. The numbered-with-transgressors (arrested as a criminal) is the humiliation that precedes the Servant\'s exaltation.</p>'
  },
  "23": {
    "43": '<p>A direct revelation: today you will be with me in paradise. The word to the penitent criminal is the most compressed eschatological promise in the Gospels: today (the dying day, no purgatorial delay), with me (personal presence with Christ, not merely a blessed state), in paradise (the garden-restored, the original Eden-with-God now restored). The dying Christ who is in the process of bearing sin for the many simultaneously promises the thief immediate eschatological fellowship. The promise grounds the community\'s confidence: if even the dying criminal is welcomed today, the resurrection-hope of all who trust Christ is secured.</p>',
    "46": '<p>A direct revelation: Father, into your hands I commit my spirit. Luke\'s Christ dies with Ps 31:5 as his final prayer — the trust-language of the righteous sufferer who commits himself to the faithful Father at death. The Father-address maintains the intimate relationship that defined the whole of Luke\'s Christological portrayal (Abba in Gethsemane, 22:42; this prayer at death). The Spirit commended to the Father\'s hands is the Spirit that will be poured out at Pentecost (Acts 2) — even in death the Son\'s Spirit remains in the Father\'s keeping, to be given back in the resurrection and then poured out on the community.</p>'
  },
  "24": {
    "27": '<p>A direct revelation: beginning with Moses and all the Prophets he interpreted to them in all the Scriptures the things concerning himself. The risen Christ\'s Emmaus hermeneutic is the epistemological key to Luke\'s entire Gospel: the OT is about Christ, and only the risen Christ can unlock its true meaning. The burning hearts (v.32) indicate that proper reading of Scripture is simultaneously encounter with the risen Christ — not merely information about him but the experience of his presence through the word. Luke\'s Gospel has been narrating what the risen Christ explained: the whole story of Israel (from Genesis through the Prophets) was the long preparation for and anticipation of what Jesus accomplished in Jerusalem.</p>',
    "46": '<p>A direct revelation: it is necessary that the Christ should suffer and on the third day rise from the dead, and that repentance for the forgiveness of sins should be proclaimed in his name to all nations. The risen Christ\'s final hermeneutical statement to the disciples declares the canonical shape of the Christological narrative: suffering → resurrection is the divinely necessary arc (dei), and the worldwide mission to proclaim forgiveness in his name is its equally necessary consequence. Luke 24:46-47 is the theological thesis of Acts, which will narrate exactly this proclamation going from Jerusalem to the ends of the earth. The Christ\'s mission is complete; the community\'s mission is just beginning.'
  }
}

# Gap-fill ch 12 — all 59 verses
FILL_CH12 = {
  "12": {
    "1": "<p>&#8220;Be on your guard against the yeast of the Pharisees, which is hypocrisy&#8221; &#8212; the warning opens Luke 12&#8217;s extended discourse on authentic discipleship. Yeast as a type of pervasive influence runs from the Passover command to purge leaven (Exod 12:15, representing the old sinful life) through Paul&#8217;s use in 1 Cor 5:6&#8211;8. The Pharisees&#8217; hypocrisy &#8212; performing religion for human audiences rather than the Father &#8212; is the antithesis of the transparent life Christ calls his disciples to. The great crowd pressing around Jesus is the setting: the cost of authentic confession is high.</p>",
    "2": "<p>&#8220;There is nothing concealed that will not be disclosed&#8221; &#8212; the eschatological principle of revelation. All hidden things will be exposed at the final judgment; the theme pervades OT wisdom literature (Eccl 12:14: &#8220;God will bring every deed into judgment, including every hidden thing&#8221;; Prov 15:3). Christologically, this verse grounds the call to authenticity: the resurrection and parousia of Christ are the events that bring all things into the open. The disciples need not fear human exposure of their witness because the final disclosure is the Son of Man&#8217;s verdict (v.8).</p>",
    "3": "<p>&#8220;What you have said in the dark will be heard in the daylight&#8221; &#8212; the reversal of hiddenness in the eschatological light. The theme of light revealing what darkness concealed is central to John&#8217;s Gospel (3:20&#8211;21: &#8220;everyone who does evil hates the light, and will not come into the light for fear that their deeds will be exposed&#8221;) and to Paul&#8217;s eschatology (1 Cor 4:5: &#8220;when the Lord comes, he will bring to light what is hidden in darkness and will expose the motives of the heart&#8221;). Christ as the light of the world (John 8:12) is the one before whom all darkness yields.</p>",
    "4": "<p>&#8220;I tell you, my friends, do not be afraid of those who kill the body and after that can do no more&#8221; &#8212; the address &#8220;my friends&#8221; (<em>philoi</em>) is unique in Luke&#8217;s Gospel; Christ uses it to ground the courage-command in relational security. The asymmetry between what humans can do (kill the body only) and what God can do (v.5) reframes all persecution. The theme of courage before human authorities runs from the martyrdom tradition of the Maccabees through the Acts narrative of persecution. Christ who faced death freely (9:51: &#8220;set his face to go to Jerusalem&#8221;) models the fearlessness he calls his disciples to.</p>",
    "5": "<p>&#8220;Fear him who, after your body has been killed, has authority to throw you into Gehenna&#8221; &#8212; the fear of God as the antidote to the fear of humans. The authority to cast into Gehenna (the valley of Hinnom, symbol of final judgment since Jer 7:31&#8211;32) is the divine prerogative. Christologically significant: in John 5:22,27, this same authority to judge is given to the Son by the Father (&#8220;the Father judges no one, but has entrusted all judgment to the Son&#8230; he has given him authority to judge because he is the Son of Man&#8221;). The one who commands fear of God in v.5 is the one who exercises God&#8217;s judgment.</p>",
    "6": "<p>&#8220;Are not five sparrows sold for two pennies? Yet not one of them is forgotten by God&#8221; &#8212; the providential care of God extends to the least significant creatures of the commercial world. The sparrow-argument is from the lesser to the greater: if YHWH knows each sparrow (Ps 84:3: &#8220;even the sparrow has found a home&#8221;; Matt 10:29), how much more does the Father know each disciple. The revelation of God in this verse: the same God who sends his Son to die for humanity maintains intimate knowledge of each individual life &#8212; the cosmic and the personal are both present in the Father&#8217;s care.</p>",
    "7": "<p>&#8220;The very hairs of your head are all numbered. Don&#8217;t be afraid; you are worth more than many sparrows&#8221; &#8212; the enumeration of hairs is the OT language of divine attention to the most minute detail (1 Sam 14:45: &#8220;not a hair of his head will fall to the ground&#8221;; 2 Sam 14:11). The comparison with sparrows moves from a general principle (God knows all birds) to a specific assurance (you are of more value). The cross is the ultimate proof of this value: &#8220;God demonstrates his own love for us in this: while we were still sinners, Christ died for us&#8221; (Rom 5:8). The Father&#8217;s enumeration of hairs is the context of the Son&#8217;s self-giving.</p>",
    "8": "<p>&#8220;Whoever publicly acknowledges me before others, the Son of Man will also acknowledge before the angels of God&#8221; &#8212; the Son of Man as the eschatological advocate. This is a direct Christological claim: the Son of Man who speaks in the third person here is Jesus himself (the apocalyptic figure of Dan 7:13&#8211;14 who receives all authority from the Ancient of Days). To acknowledge Christ before humans is to be acknowledged by him before the heavenly court; the present earthly confession has eternal eschatological consequence. The connection between confession and advocacy grounds the disciples&#8217; courage for witness.</p>",
    "9": "<p>&#8220;But whoever disowns me before others will be disowned before the angels of God&#8221; &#8212; the negative counterpart: the Son of Man as the eschatological judge who mirrors back to each person their response to Jesus. The symmetry of acknowledgment/disowning is the basis of all missiology: the stakes of accepting or rejecting Christ are ultimate. Peter&#8217;s denial (22:57&#8211;60) and restoration (John 21:15&#8211;17) are the living narrative of this warning and its provision &#8212; even denial does not foreclose repentance and restoration through Christ&#8217;s intercession.</p>",
    "10": "<p>&#8220;Everyone who speaks a word against the Son of Man will be forgiven, but anyone who blasphemes against the Holy Spirit will not be forgiven&#8221; &#8212; the one unforgivable sin is the settled rejection of the Spirit&#8217;s testimony to Christ. Speaking against the Son of Man (misunderstanding Jesus in his earthly humility) is forgivable &#8212; as Paul&#8217;s pre-conversion opposition was (1 Tim 1:13: &#8220;I was shown mercy because I acted in ignorance and unbelief&#8221;). But hardening against the Spirit&#8217;s clear testimony &#8212; attributing divine works to demonic power &#8212; is the self-excluding rejection of the only agent through whom forgiveness comes.</p>",
    "11": "<p>&#8220;When you are brought before synagogues, rulers and authorities, do not worry about how you will defend yourselves&#8221; &#8212; the assurance for the disciples facing official persecution. The progression from synagogues to rulers to authorities charts the expanding scope of the Acts narrative (Acts 4: synagogue/Sanhedrin; Acts 24&#8211;26: Roman governors and kings). The &#8220;do not worry&#8221; command echoes the earlier do-not-worry of vv.22&#8211;31 &#8212; both forms of anxiety (material and legal) are addressed by the same Father-assurance. Christ promises the Spirit&#8217;s provision before the courts he himself faced.</p>",
    "12": "<p>&#8220;For the Holy Spirit will teach you at that time what you should say&#8221; &#8212; the Paraclete-promise in embryonic form; John 14:26 makes it explicit (&#8220;the Advocate, the Holy Spirit, whom the Father will send in my name, will teach you all things&#8221;). The Spirit who was upon Jesus at his baptism (3:22) and who led him through the wilderness (4:1) is the same Spirit Jesus promises to his disciples for their own trials. The provision is not a script but a person &#8212; the Spirit&#8217;s real-time guidance is the Christ-community&#8217;s equivalent of Jesus&#8217;s own Spirit-filled wisdom in conflict.</p>",
    "13": "<p>The man in the crowd asking Jesus to adjudicate an inheritance dispute is a type of those who seek to use Jesus for worldly advantage rather than receive him as Savior. The inheritance dispute is framed by the law of Moses (Deut 21:17: firstborn receives double share), which does not resolve all cases. The man wants Jesus as a legal arbiter, not as the Lord of the kingdom. His question is a foil for the Rich Fool parable: both the questioner and the fool are focused on earthly inheritance rather than the wealth that matters before God (v.21).</p>",
    "14": "<p>&#8220;Man, who appointed me a judge or an arbiter between you?&#8221; &#8212; Christ refuses the role of earthly legal adjudicator. The refusal echoes Moses&#8217;s rhetorical question when challenged (Exod 2:14: &#8220;Who made you ruler and judge over us?&#8221;) &#8212; ironically, Christ is the one appointed as judge of all (John 5:22), but his kingdom is not of this world (John 18:36). He refuses to adjudicate property disputes because his mission is to address the deeper dispute &#8212; the claim of God on the human heart. The question reframes the entire ministry: Christ does not come to manage worldly affairs but to transform the heart toward God.</p>",
    "15": "<p>&#8220;Watch out! Be on your guard against all kinds of greed; life does not consist in an abundance of possessions&#8221; &#8212; the Christological ethics of wealth begins with a direct command against greed (<em>pleonexia</em>, the desire for more). The theme is grounded in the Tenth Commandment (Exod 20:17: covet not) and reaches its NT fullness in 1 Tim 6:6&#8211;10 (&#8220;godliness with contentment is great gain&#8221;). Christ himself is the counter-image of acquisitiveness: &#8220;the Son of Man has nowhere to lay his head&#8221; (9:58); &#8220;he became poor so that through his poverty you might become rich&#8221; (2 Cor 8:9). The abundant life (John 10:10) is not defined by possessions.</p>",
    "16": "<p>The rich man whose land produced abundantly is not condemned for the harvest but for his response to it. The parable is a type of the human response to blessing when God is absent from the calculation. The abundant harvest echoes the covenant blessings of Deut 28:1&#8211;14 &#8212; the problem is not the blessing but the direction of the heart in response to it. The man&#8217;s question (&#8220;what shall I do?&#8221;) is the right question asked without reference to God &#8212; and the parable turns on the answer God provides (v.20) vs. the answer the man devises.</p>",
    "17": "<p>&#8220;What shall I do? I have no place to store my crops&#8221; &#8212; the rich fool&#8217;s interior monologue reveals the problem: the word &#8220;I&#8221; dominates his reasoning, and God is entirely absent. The self-referential planning is the shadow of the autonomy that began in Gen 3 (the human attempt to manage life independently of the Creator). The crops he cannot store are the blessing of God (Deut 28:12: &#8220;the LORD will open the heavens, the storehouse of his bounty&#8230; to bless all the work of your hands&#8221;), received without reference to the Giver.</p>",
    "18": "<p>&#8220;I will tear down my barns and build bigger ones, and there I will store my surplus grain&#8221; &#8212; the expansion strategy is the logic of earthly security maximized. The word &#8220;I&#8221; appears five times in vv.17&#8211;19; the fool&#8217;s monologue is a five-fold assertion of self-sufficiency. The tearing down and building bigger echoes the Tower of Babel ambition (Gen 11:4) &#8212; the human project of constructing permanent security in the present order. Christ as the true security (Col 3:3: &#8220;your life is now hidden with Christ in God&#8221;) is the alternative to the barn-building strategy.</p>",
    "19": "<p>&#8220;You have plenty of grain laid up for many years. Take life easy; eat, drink and be merry&#8221; &#8212; the Epicurean conclusion (&#8220;eat and drink, for tomorrow we die&#8221;; cf. 1 Cor 15:32) is the natural result of earthly security without God. The irony is profound: the man pronounces security (&#8220;many years&#8221;) on the very night his life will be demanded. The phrase &#8220;eat, drink and be merry&#8221; inverts the Wisdom tradition: Prov 27:1 (&#8220;do not boast about tomorrow, for you do not know what a day may bring&#8221;). The fool&#8217;s self-congratulation is the shadow of false security that the cross exposes as futile.</p>",
    "20": "<p>&#8220;You fool! This very night your life will be demanded from you&#8221; &#8212; God&#8217;s direct address in the parable. The divine voice breaking into human self-congratulation is the prophetic pattern: Nathan to David (2 Sam 12:7), Isa 5:8&#8211;9 (&#8220;woe to you who add house to house&#8221;). The word &#8220;fool&#8221; (<em>aphr&#333;n</em>) is the one who lives without reference to God (Ps 14:1: &#8220;the fool says in his heart, there is no God&#8221;). The demanded life (<em>psychē</em>) is the soul/life that cannot be stored in barns &#8212; and can only be given by the one who is the resurrection and the life (John 11:25).</p>",
    "21": "<p>&#8220;This is how it will be with whoever stores up things for themselves but is not rich toward God&#8221; &#8212; the application. &#8220;Rich toward God&#8221; (<em>eis theon</em>) is the countercultural wealth the parable promotes. The riches toward God are faith, obedience, generosity, and love &#8212; stored in heaven where moth and rust cannot destroy (v.33; Matt 6:20). The Christological ground: to be rich toward God is to trust the Son through whom all things are held together (Col 1:17) rather than to trust the barns that cannot hold the soul. Christ himself is the treasure &#8212; &#8220;in him are hidden all the treasures of wisdom and knowledge&#8221; (Col 2:3).</p>",
    "22": "<p>&#8220;Therefore I tell you, do not worry about your life, what you will eat; or about your body, what you will wear&#8221; &#8212; the &#8220;therefore&#8221; connects the anti-anxiety teaching directly to the Rich Fool parable: since life cannot be secured by possessions, the whole framework of anxious acquisition is misguided. The teaching develops Ps 37:1&#8211;7 (&#8220;do not fret&#8230; trust in the LORD and do good&#8230; delight yourself in the LORD&#8221;) and anticipates Phil 4:6&#8211;7 (&#8220;do not be anxious about anything, but in every situation, by prayer and petition, present your requests to God&#8221;). Christ who became food for our hunger (John 6:35) addresses anxiety about food.</p>",
    "23": "<p>&#8220;For life is more than food, and the body more than clothes&#8221; &#8212; the theological argument for non-anxiety: the Creator who gave the greater gift (life, body) will surely provide the lesser gifts (food, clothing). The argument from the greater to the lesser is a standard Jewish hermeneutical principle (<em>kal wa-homer</em>); Jesus uses it here to establish the Father&#8217;s providential care as self-evident from creation. The one who sustains all life (Ps 104:14&#8211;15: &#8220;he makes grass grow for the cattle, and plants for people to cultivate&#8230; wine that gladdens human hearts&#8221;) will sustain his children.</p>",
    "24": "<p>&#8220;Consider the ravens: they do not sow or reap, they have no storeroom or barn; yet God feeds them&#8221; &#8212; the raven as the paradigm case of divine provision. Ravens were unclean birds (Lev 11:15) yet God fed Elijah through ravens at the Kerith brook (1 Kgs 17:4: &#8220;I have directed the ravens to supply you with food there&#8221;). The unclean birds fed by God are a type of the Gentiles fed by divine provision through Christ &#8212; the one who said &#8220;I am the bread of life&#8221; (John 6:35) provides for those outside the covenant as well as within it. The ravens are the shadow of universal divine provision.</p>",
    "25": "<p>&#8220;Who of you by worrying can add a single hour to your life?&#8221; &#8212; the futility argument against anxiety. Worry cannot extend life even by the smallest measure; it cannot accomplish what it seeks. The argument is not merely pragmatic (worry doesn&#8217;t work) but theological (life is in God&#8217;s hands, not ours). Jesus who has life in himself (John 5:26: &#8220;as the Father has life in himself, so he has granted the Son to have life in himself&#8221;) addresses the anxiety about life&#8217;s duration. The one who is the resurrection and the life (John 11:25) renders anxious extension-attempts futile.</p>",
    "26": "<p>&#8220;Since you cannot do this very little thing, why do you worry about the rest?&#8221; &#8212; the reductio ad absurdum of anxiety: if you cannot perform even the smallest act of extending life, why do you worry about all the larger provisions? The logic reorients from human effort to divine provision. The teaching is preparatory for the Gethsemane moment when Jesus himself models non-anxious trust: &#8220;not my will, but yours be done&#8221; (22:42) is the ultimate expression of the radical dependence on the Father that this verse advocates. Christ models what he teaches.</p>",
    "27": "<p>&#8220;Consider how the wild flowers grow. They do not labour or spin. Yet I tell you, not even Solomon in all his splendour was dressed like one of these&#8221; &#8212; Solomon, the paradigm of earthly wealth and splendor (1 Kgs 10:4&#8211;7), is explicitly surpassed by a wildflower. The comparison is startling: the created beauty that glorifies the Creator exceeds even the most elaborate human construction of beauty. Christ as the new Solomon (the greater son of David, Matt 12:42: &#8220;one greater than Solomon is here&#8221;) is himself the ultimate beauty &#8212; and his Father&#8217;s clothing of the fields reflects the Father&#8217;s willingness to clothe his Son&#8217;s followers.</p>",
    "28": "<p>&#8220;If that is how God clothes the grass of the field, which is here today and tomorrow is thrown into the fire, how much more will he clothe you &#8212; you of little faith!&#8221; &#8212; the argument from the lesser (grass/flowers, temporary) to the greater (disciples, eternal). The phrase &#8220;of little faith&#8221; (<em>oligopistos</em>) is gentle rebuke &#8212; the disciples have faith, but their faith is too small for the Father&#8217;s provision. The one who calls his disciples &#8220;little flock&#8221; (v.32) is also the one who calls them &#8220;of little faith&#8221; &#8212; both terms are tender rebukes from the shepherd who cares more than they can imagine.</p>",
    "29": "<p>&#8220;And do not set your heart on what you will eat or drink; do not worry about it&#8221; &#8212; the repeated command reinforces its importance. The &#8220;setting the heart&#8221; language (<em>meteorizesthe</em>, &#8220;do not be lifted up in anxious care&#8221;) points to the underlying problem of misplaced devotion. The disciples&#8217; hearts are to be set on the kingdom (v.31) rather than on provisions. The theme of right object-of-devotion is the Shema applied to anxiety: love the Lord your God with all your heart means your heart is not anxiously divided among lesser things (Deut 6:5&#8211;6; 1 Cor 7:35).</p>",
    "30": "<p>&#8220;For the pagan world runs after all such things, and your Father knows that you need them&#8221; &#8212; the contrast between pagan anxiety and filial trust. The &#8220;pagan world&#8221; (<em>ta ethnē tou kosmou</em>) pursues provision through anxious effort because they do not know a Father who provides. The disciples&#8217; access to the Father through Christ is the ground of their differentiation: they have received the Spirit of adoption (Rom 8:15: &#8220;the Spirit you received brought about your adoption to sonship. And by him we cry, Abba, Father&#8221;). The &#8220;your Father knows&#8221; is the Christological gift: the disciples now address God as Father because the Son has made him known (John 1:18).</p>",
    "31": "<p>&#8220;But seek his kingdom, and these things will be given to you as well&#8221; &#8212; the positive reorientation after the negatives (don&#8217;t worry, don&#8217;t set heart on food/drink). The kingdom-priority is the practical outworking of the first commandment: God first, all other things in their proper place. Christ who proclaims the kingdom &#8220;is not far from each one of us&#8221; (Acts 17:27); to seek the kingdom is to seek the King. The promise &#8220;these things will be given to you as well&#8221; is the covenant economy: seeking the Giver rather than the gifts results in receiving both the Giver and the gifts.</p>",
    "32": "<p>&#8220;Do not be afraid, little flock, for your Father has been pleased to give you the kingdom&#8221; &#8212; the tender term &#8220;little flock&#8221; (<em>to mikron poimnion</em>) casts Jesus in the role of the divine Shepherd (Ps 23; Ezek 34; John 10) and the disciples as his flock. The Father&#8217;s pleasure (<em>eudokēsen</em>) in giving the kingdom is the same language of the baptism (3:22: &#8220;with you I am well pleased&#8221;) applied now to the disciples&#8217; inheritance. The gift of the kingdom is not earned but given &#8212; the Christological logic of grace: the Father who is pleased to give the Son is pleased to give the kingdom through the Son.</p>",
    "33": "<p>&#8220;Sell your possessions and give to the poor. Provide purses for yourselves that will not wear out, a treasure in heaven that will never fail&#8221; &#8212; the practical application of kingdom priority. The command to sell and give is grounded in the Jubilee ethic of Lev 25 and the Deuteronomic vision of a community without poverty (Deut 15:4). The treasure in heaven that does not fail is the eschatological reversal of earthly wealth &#8212; stored through generosity, not accumulation. Christ who &#8220;became poor&#8221; for our sake (2 Cor 8:9) models the divestment he commands; the cross is the ultimate treasury-deposit of selfless giving.</p>",
    "34": "<p>&#8220;For where your treasure is, there your heart will be also&#8221; &#8212; the diagnostic principle: the location of one&#8217;s treasure reveals the location of one&#8217;s heart. The theme of the heart&#8217;s true object is the test of covenant faithfulness throughout the OT (Deut 10:12&#8211;13: &#8220;what does the LORD your God ask of you but to fear the LORD your God, to walk in obedience to him, to love him, to serve him with all your heart and with all your soul&#8221;). Christ as the &#8220;pearl of great price&#8221; (Matt 13:45&#8211;46) is the treasure worth selling everything to possess; when he is the treasure, the heart is properly located.</p>",
    "35": "<p>&#8220;Be dressed ready for service and keep your lamps burning&#8221; &#8212; the watchfulness imagery opens the eschatological section of Luke 12. Being dressed (<em>osphyes perizōsmenai</em>, literally &#8220;loins girded&#8221;) is the Exodus posture: the Israelites ate the Passover &#8220;with your cloak tucked into your belt, your sandals on your feet and your staff in your hand&#8221; (Exod 12:11). The burning lamps recall the parable of the ten virgins (Matt 25:1&#8211;13). Readiness for the returning master is the posture of those who know the kingdom has been given (v.32) but awaits its consummation.</p>",
    "36": "<p>&#8220;Like servants waiting for their master to return from a wedding banquet, so that when he comes and knocks they can immediately open the door for him&#8221; &#8212; the master at the wedding banquet is a type of the bridegroom Christ of the parable (John 3:29; Rev 19:7&#8211;9). The returning master is the parousia of Christ; the open door is the readiness of faith. The servants&#8217; waiting mirrors the posture of the early church: &#8220;Maranatha, come, Lord Jesus&#8221; (1 Cor 16:22; Rev 22:20). Every generation of the church is the generation of watchful servants waiting at the door.</p>",
    "37": "<p>&#8220;It will be good for those servants whose master finds them watching when he comes. Truly I tell you, he will dress himself to serve, will have them recline at the table and will come and wait on them&#8221; &#8212; the parousia reversal: the returning master serves his servants. This is the most startling image in the watchfulness parables: the Lord dresses and serves. It is what Jesus does at the Last Supper (John 13:4&#8211;5: &#8220;he got up from the meal, took off his outer clothing, and wrapped a towel around his waist&#8221;). The parousia-service is the eschatological fulfillment of the incarnation&#8217;s servant pattern &#8212; the Son who came to serve will serve his people fully in the age to come.</p>",
    "38": "<p>&#8220;It will be good for those servants whose master finds them ready, even if he comes in the middle of the night or toward daybreak&#8221; &#8212; the second and third watches of the night are the most demanding hours for vigilance. The extended watchfulness required mirrors the patient endurance of faith across history (Heb 10:36&#8211;37: &#8220;you need to persevere so that when you have done the will of God, you will receive what he has promised. For, in just a little while, he who is coming will come and will not delay&#8221;). The blessing of readiness is not restricted to one generation &#8212; every generation that maintains watchfulness is blessed.</p>",
    "39": "<p>&#8220;If the owner of the house had known at what hour the thief was coming, he would not have let his house be broken into&#8221; &#8212; the parable of the thief shifts from the servant&#8217;s perspective to the householder&#8217;s. The unexpected hour of the thief is used in both NT eschatological passages (1 Thess 5:2: &#8220;the day of the Lord will come like a thief in the night&#8221;; 2 Pet 3:10; Rev 3:3; 16:15) and by Jesus himself. The image of Christ as a thief is not threatening but challenging: his return will be unexpected, and only those who maintain readiness will be prepared rather than caught off-guard.</p>",
    "40": "<p>&#8220;You also must be ready, because the Son of Man will come at an hour when you do not expect him&#8221; &#8212; the direct application. The Son of Man coming unexpectedly is the Danielic figure (Dan 7:13&#8211;14) appearing at the eschatological moment. The disciples&#8217; readiness is grounded not in calculation (predicting the hour) but in character (living the watchful life). The one who commands readiness is the one who will come: Christ as both the teacher of the parable and the subject of the parousia is the single person who invites and rewards faithfulness.</p>",
    "41": "<p>Peter&#8217;s question (&#8220;Lord, are you telling this parable to us, or to everyone?&#8221;) reveals the disciples&#8217; interest in whether the watchfulness-demands apply exclusively to them as leaders or generally. The question is a pastoral one: leadership responsibility carries greater accountability (v.48: &#8220;from everyone who has been given much, much will be demanded&#8221;). Jesus&#8217;s response shifts to the faithful manager parable, implicitly addressing Peter&#8217;s leadership role. The question itself demonstrates the disciples&#8217; self-awareness as a distinct community called to specific responsibility under the returning Lord.</p>",
    "42": "<p>&#8220;Who then is the faithful and wise manager, whom the master puts in charge of his servants to give them their food allowance at the proper time?&#8221; &#8212; the manager (<em>oikonomos</em>, steward/household administrator) is the type of the church&#8217;s leadership. Faithfulness and wisdom are the two required qualities: faithfulness (pistis, trust and reliability) to the master; wisdom (<em>phronimos</em>) in the daily management. Paul applies the same stewardship language to apostolic ministry: &#8220;it is required that those who have been given a trust must prove faithful&#8221; (1 Cor 4:2). Christ is the master over whose household all pastoral leadership is appointed.</p>",
    "43": "<p>&#8220;It will be good for that servant whom the master finds doing so when he returns&#8221; &#8212; the blessing falls on the servant found doing the assigned work at the master&#8217;s return. The pattern of the parousia-blessing: faithfulness in the hidden time of waiting is rewarded at the moment of return. The theme runs through the parable of the talents/minas (19:15&#8211;19) and the Sheep/Goats judgment (Matt 25:34&#8211;40): the evaluation at the return is based on the pattern of life during the interim, not on last-minute adjustment. The servant found doing is the servant formed by the master&#8217;s character.</p>",
    "44": "<p>&#8220;Truly I tell you, he will put him in charge of all his possessions&#8221; &#8212; the eschatological promotion. The faithful manager of a few is given the governance of all &#8212; the pattern of Joseph (appointed over all Egypt, Gen 41:41), Daniel (appointed over all the kingdom, Dan 6:3), and the disciples (Matt 19:28: &#8220;you will sit on twelve thrones, judging the twelve tribes of Israel&#8221;). The governance of all is participation in Christ&#8217;s own reign (Rev 3:21: &#8220;to the one who is victorious, I will give the right to sit with me on my throne&#8221;). Faithful stewardship now leads to co-reign with Christ.</p>",
    "45": "<p>The wicked servant&#8217;s reasoning (&#8220;my master is taking a long time in coming&#8221;) is the logic of delayed-parousia moral failure &#8212; the mirror image of the faithful servant. The violence he enacts against fellow servants and his drunken feasting are the practical results of living as if Christ will not return &#8212; the deferred eschatology that produces self-indulgence and abuse of authority. The same pattern recurs in 2 Pet 3:3&#8211;4 (&#8220;scoffers&#8230; will say, Where is this coming he promised?&#8221;). The distance between waiting (v.36) and abandoning the wait (v.45) is the distance between faithfulness and apostasy.</p>",
    "46": "<p>&#8220;The master of that servant will come on a day when he does not expect him and at an hour he is not ready for him. He will cut him to pieces and assign him a place with the unbelievers&#8221; &#8212; the judgment on the unfaithful servant is severe and unexpected &#8212; the very unpreparedness he cultivated through delay becomes his condemnation. The &#8220;cutting to pieces&#8221; and assignment with the unbelievers is the language of final judgment: exclusion from the kingdom of the returning Lord. The Christological warning: the one who delays reckoning with Jesus is not avoiding him &#8212; he is meeting him unprepared.</p>",
    "47": "<p>&#8220;The servant who knows the master&#8217;s will and does not get ready or does not do what the master wants will be beaten with many blows&#8221; &#8212; knowledge of the will without obedience increases guilt. The principle runs from Deut 28&#8217;s covenant curse-structure through James 4:17 (&#8220;if anyone, then, knows the good they ought to do and doesn&#8217;t do it, it is sin for them&#8221;) and Rom 2:12&#8211;13. The disciples who know the master&#8217;s will (having received the teaching of this entire discourse) bear greater responsibility than those who have not heard. Christ as the teacher intensifies the accountability of his disciples.</p>",
    "48": "<p>&#8220;From everyone who has been given much, much will be demanded; and from the one who has been entrusted with much, much more will be asked&#8221; &#8212; the principle of stewardship-accountability that grounds all Christian leadership ethics. Those entrusted with the gospel, the church, the Scriptures &#8212; given the revelation of God in Christ &#8212; are held to a higher accounting. The theme of proportional responsibility runs from the Deuteronomic covenant (blessed to be a blessing, Gen 12:2; Deut 4:7&#8211;9) through James 3:1 (&#8220;not many of you should become teachers, my fellow believers, because you know that we who teach will be judged more strictly&#8221;).</p>",
    "49": "<p>&#8220;I have come to bring fire on the earth, and how I wish it were already kindled!&#8221; &#8212; the fire Christ brings is the baptism of the Spirit and fire that John promised (3:16: &#8220;he will baptize you with the Holy Spirit and fire&#8221;) and the refining fire of judgment (Mal 3:2: &#8220;he will be like a refiner&#8217;s fire&#8221;). Christ&#8217;s longing for the fire to be kindled is his longing for the passion that will accomplish it &#8212; the cross as the source of the Spirit&#8217;s Pentecost-fire. The fire-wish anticipates his baptism-constraint in v.50: both the desire and the cost are held together in one verse.</p>",
    "50": "<p>&#8220;But I have a baptism to undergo, and what constraint I am under until it is completed!&#8221; &#8212; the &#8220;baptism&#8221; is the passion: burial under the waters of death (Rom 6:3&#8211;4: &#8220;we were baptized into his death&#8230; buried with him through baptism into death&#8221;). The constraint (<em>syneχomai</em>, &#8220;I am held/hemmed in&#8221;; cf. Phil 1:23: &#8220;I am torn between the two&#8221;) reveals the inner life of the incarnate Son under the pressure of his mission &#8212; not reluctance but intentional movement toward the cross. The passion is not thrust upon him; he moves toward it with resolve (9:51) and with longing.</p>",
    "51": "<p>&#8220;Do you think I came to bring peace on earth? No, I tell you, but division&#8221; &#8212; the divisive sword of the gospel is not a contradiction of the angels&#8217; &#8220;peace on earth&#8221; announcement (2:14) but its fulfillment through conflict. The peace Christ brings (Eph 2:14: &#8220;he himself is our peace&#8221;; John 14:27: &#8220;I give you my peace&#8221;) comes through the sword of the word (Heb 4:12: &#8220;the word of God is alive and active. Sharper than any double-edged sword&#8221;) that divides truth from falsehood, the kingdom from the world, and even families from one another.</p>",
    "52": "<p>&#8220;From now on there will be five in one family divided against each other&#8221; &#8212; the &#8220;from now on&#8221; (<em>apo tou nyn</em>) marks the eschatological present: the arrival of Christ creates the decisive division in human relationships and communities. The theme of the family divided by allegiance to God runs from Deut 33:9 (Levi: &#8220;who said of his father and mother, I have no regard for them&#8221;) through Matt 10:34&#8211;37 (&#8220;do not suppose that I have come to bring peace to the earth&#8221;). The division is not Christ&#8217;s preference but the inevitable result of the absolute claim he makes on human loyalty.</p>",
    "53": "<p>&#8220;They will be divided, father against son and son against father&#8221; &#8212; a near-quotation of Mic 7:6 (&#8220;a man&#8217;s enemies are the members of his own household&#8221;), cited explicitly in Matt 10:35&#8211;36. Micah 7 is a prophetic lament about social disintegration in Israel that reaches its resolution in Mic 7:18&#8211;20 with the God who pardons sin and remains faithful to the covenant. Jesus&#8217;s citation of Mic 7:6 identifies his ministry as the climactic fulfillment of the covenant conflict that Micah described &#8212; the division that precedes the eschatological restoration.</p>",
    "54": "<p>&#8220;When you see a cloud rising in the west, immediately you say, It&#8217;s going to rain, and it does&#8221; &#8212; the ability to read weather signs introduces the rebuke about failing to read the signs of the times. The cloud from the west (Mediterranean) was the reliable predictor of rain in Palestine (1 Kgs 18:44: Elijah&#8217;s servant sees &#8220;a cloud as small as a man&#8217;s hand rising from the sea&#8221; before the great rain). The weather-reading expertise of Jesus&#8217;s audience is not criticized; their failure to apply the same attentiveness to the signs of the kingdom&#8217;s presence is.</p>",
    "55": "<p>&#8220;And when the south wind blows, you say, It&#8217;s going to be hot, and it is&#8221; &#8212; the south wind (<em>notos</em>) from the desert was the reliable predictor of heat in the Levant. The reliability of natural signs &#8212; which the crowd reads accurately &#8212; is contrasted with their failure to read the spiritual signs before them: the healing of the sick, the preaching of good news to the poor, the raising of the dead &#8212; all pointing to the presence of the long-awaited Servant-Messiah. The irony of the sign-readers who miss the greatest sign is the Johannine pattern (John 2:11; 20:30&#8211;31).</p>",
    "56": "<p>&#8220;Hypocrites! You know how to interpret the appearance of the earth and the sky. How is it that you don&#8217;t know how to interpret this present time?&#8221; &#8212; the accusation of hypocrisy shifts the weather-reading from incompetence to willful blindness. The failure to read &#8220;this present time&#8221; (<em>ton kairon touton</em>) is the failure to recognize the <em>kairos</em> &#8212; the decisive moment of the kingdom&#8217;s arrival in Jesus. The Christological claim is implicit: reading the present time correctly requires recognizing Jesus as the one in whom the <em>kairos</em> is concentrated &#8212; the fullness of time (Gal 4:4: &#8220;when the set time had fully come&#8221;).</p>",
    "57": "<p>&#8220;Why don&#8217;t you judge for yourselves what is right?&#8221; &#8212; the call to right judgment about the situation echoes the earlier question (v.14: &#8220;who made me a judge?&#8221;) in reverse: there Jesus refused earthly arbitration; here he calls the people to exercise their own moral-spiritual discernment. The capacity to judge rightly is the fruit of the wisdom that Christ brings &#8212; and the failure to judge the present time correctly is the failure to receive the wisdom that has come in person (Col 2:3: &#8220;in whom are hidden all the treasures of wisdom and knowledge&#8221;).</p>",
    "58": "<p>&#8220;As you are going with your adversary to the magistrate, try hard to be reconciled on the way, or your adversary may drag you off to the judge&#8221; &#8212; the urgent wisdom of the legal illustration. The immediate reading: settle disputes before they escalate to formal judgment. The eschatological reading: the urgency of reconciliation with God before the final judgment is the deeper point &#8212; the opportunity for reconciliation exists now, in the interval before the court. Christ as the mediator (1 Tim 2:5: &#8220;there is one God and one mediator between God and mankind, the man Christ Jesus&#8221;) is the one through whom present reconciliation is possible.</p>",
    "59": "<p>&#8220;I tell you, you will not get out until you have paid the last penny&#8221; &#8212; the legal imagery concludes with the absolute finality of the debt owed. The last penny (<em>lepton</em>) is the smallest Roman coin; the image of paying to the last penny evokes the complete accounting required at the eschatological court. The verse is a warning about the full weight of obligation before God &#8212; and simultaneously points to the one who paid the full debt on behalf of others: Christ&#8217;s atonement is the paying of the last penny (Col 2:14: &#8220;he has taken it away, nailing it to the cross&#8221;).</p>"
  }
}

# Gap-fill ch 13 — all 35 verses
FILL_CH13 = {
  "13": {
    "1": "<p>The Galileans whose blood Pilate mixed with their sacrifices is a historical event otherwise unrecorded outside Luke. The sacrifices interrupted by Pilate&#8217;s violence recall the covenant context: Israel brought sacrifices to draw near to God; the desecration of the sacrificial act by political violence is an extreme instance of the sacred and the brutal intersecting. Jesus&#8217;s response reframes the question away from theodicy toward eschatological urgency &#8212; not &#8220;why did this happen to them?&#8221; but &#8220;what does this require of you?&#8221;</p>",
    "2": "<p>&#8220;Do you think that these Galileans were worse sinners than all the other Galileans because they suffered this way?&#8221; &#8212; Jesus refuses the theodicy framework that connects specific suffering with specific sin (Job 22:4&#8211;5; John 9:2&#8211;3: &#8220;who sinned, this man or his parents, that he was born blind?&#8221;). The assumption being rejected is the Deuteronomic retribution principle applied mechanically: that all suffering is divine punishment for identifiable sin. Christ&#8217;s answer (&#8220;no&#8221;) clears the ground for the true application: universal human vulnerability and universal need for repentance.</p>",
    "3": "<p>&#8220;I tell you, no! But unless you repent, you too will all perish&#8221; &#8212; the sharp turn from theodicy to eschatological urgency. The word &#8220;perish&#8221; (<em>apollymi</em>) carries both physical and eschatological meaning in Luke (13:3,5; 15:17,24: &#8220;lost&#8221;/&#8220;dead&#8221;; 19:10: &#8220;the Son of Man came to seek and save the lost&#8221;). The urgency of repentance before God is the same urgency that the prophets proclaimed &#8212; and the same that John proclaimed at Jesus&#8217;s approach (3:8: &#8220;produce fruit in keeping with repentance&#8221;). Christ as the one before whom all must give account (2 Cor 5:10) grounds the urgency.</p>",
    "4": "<p>&#8220;Or those eighteen who died when the tower in Siloam fell on them &#8212; do you think they were more guilty than all the others living in Jerusalem?&#8221; &#8212; the second theodicy-refusal. The tower of Siloam collapse was an accident, not a deliberate political act; yet Jesus applies the same theological principle. The juxtaposition of Pilate&#8217;s violence (human agency) and the tower&#8217;s fall (apparently &#8220;natural&#8221; disaster) covers the full spectrum of catastrophic death &#8212; none of it is a precise measure of the victim&#8217;s guilt. The equal application of &#8220;unless you repent, you will all perish&#8221; to both cases emphasizes the universal human need.</p>",
    "5": "<p>&#8220;I tell you, no! But unless you repent, you too will all perish&#8221; &#8212; the doubled call to repentance is a rhetorical device emphasizing the urgency (the same word twice frames the section). The repetition mirrors the prophetic double-call pattern (Isa 40:1: &#8220;comfort, comfort my people&#8221;; Jer 7:4: the temple-sermon repetition). Christ as the prophet who calls to repentance is also the one who offers the alternative to perishing (John 3:16: &#8220;that whoever believes in him shall not perish but have eternal life&#8221;). The warning and the gospel are inseparable.</p>",
    "6": "<p>The fig tree parable (a man with a fig tree in his vineyard, three years of no fruit) is a type of Israel under divine examination. The fig tree represents Israel in prophetic literature (Jer 8:13: &#8220;there are no figs on the vine. The leaves are withered. What I have given them will be taken from them&#8221;; Hos 9:10: &#8220;I found Israel like grapes in the desert; I saw your ancestors like the early fruit on the fig tree&#8221;; Mic 7:1). The three years of fruitlessness may reflect the three years of Jesus&#8217;s ministry &#8212; the fig tree is Israel in the time of the visitation.</p>",
    "7": "<p>&#8220;For three years now I&#8217;ve been coming to look for fruit on it and haven&#8217;t found any. Cut it down! Why should it use up the soil?&#8221; &#8212; the owner&#8217;s impatience voices divine judgment after a sufficient period of patience. The vineyard-owner is the Father (cf. Isa 5:1&#8211;7: &#8220;my loved one had a vineyard&#8230; I expected good grapes, but it yielded only bad fruit&#8221;). The command to cut it down is the judgment of 70 AD &#8212; the destruction of Jerusalem and the Temple &#8212; already visible in the shadow of Jesus&#8217;s ministry. The three-year period mirrors the ministry&#8217;s length and heightens the urgency of v.9.</p>",
    "8": "<p>&#8220;Sir, leave it alone for one more year, and I&#8217;ll dig around it and fertilise it&#8221; &#8212; the gardener&#8217;s intercession is the Christological center of the parable. Christ as the intercessor before the Father&#8217;s judgment pleads for one more year of grace. The image of the gardener digging and fertilizing is the intensive pastoral work of the ministry &#8212; the same work that is the theme of Ezek 34 (the divine shepherd seeking the lost sheep). The &#8220;one more year&#8221; is the grace-period of repentance-opportunity; the parable does not resolve whether it is taken.</p>",
    "9": "<p>&#8220;If it bears fruit next year, fine! If not, then cut it down&#8221; &#8212; the open ending is deliberate. The parable does not tell the outcome; it leaves the hearer in the position of the fig tree in the year of grace &#8212; the outcome depends on their response to Jesus&#8217;s ministry. The conditional &#8220;if&#8230; if not&#8221; is the shape of the gospel&#8217;s offer and judgment: grace is extended and the cross is the ultimate intercessory act, but the response determines the outcome. The unresolved ending is Luke&#8217;s literary strategy for placing the audience within the story&#8217;s decision-point.</p>",
    "10": "<p>The Sabbath synagogue setting for the healing of the crippled woman establishes the official, public character of the encounter. Jesus teaching in the synagogue on the Sabbath is his regular practice (4:16&#8211;21; 6:6) &#8212; the place of covenant instruction becomes the place of covenant fulfillment. The presence of both Jesus (teaching the word) and the woman (needing liberation) in the same space creates the encounter that the parable of the fig tree has been preparing: the tree that has not yet been cut down is about to receive the digging and fertilizing of the gardener&#8217;s care.</p>",
    "11": "<p>The woman bent double (<em>synkyptousa</em>, bent forward) for eighteen years by a spirit of infirmity is the picture of a humanity curved in on itself (Luther&#8217;s <em>homo incurvatus in se</em>) by the weight of spiritual bondage. Eighteen years echoes the eighteen who died in the tower&#8217;s fall (v.4) &#8212; Luke&#8217;s deliberate numerical link. The spirit&#8217;s binding (v.16: Satan has kept her bound) places the condition in the cosmic conflict: the woman&#8217;s infirmity is not merely physical but part of the spiritual oppression that Christ came to release (4:18: &#8220;to set the oppressed free&#8221;).</p>",
    "12": "<p>&#8220;Woman, you are set free from your infirmity&#8221; &#8212; Jesus calls her forward and speaks freedom before laying hands on her. The word of liberation precedes the physical touch &#8212; establishing that the healing is by divine authority, not physical technique. The &#8220;set free&#8221; (<em>apolylysai</em>) is the Jubilee-release language (Lev 25:10: &#8220;proclaim liberty throughout the land&#8221;) that Jesus claimed in 4:18. He is the one who sets the oppressed free &#8212; including this woman, bound by Satan for eighteen years, who is here given her Jubilee.</p>",
    "13": "<p>&#8220;He put his hands on her, and immediately she straightened up and praised God&#8221; &#8212; the laying on of hands is the gesture of blessing (Jacob blessing Joseph&#8217;s sons, Gen 48:14) and of healing throughout the ministry. Her immediate straightening reverses the years of being bent; the praise of God is the natural response to liberation. The pattern &#8212; Jesus acts, person is restored, God is glorified &#8212; is the consistently Lukan doxological structure of healing (17:15; 18:43; Acts 3:8). The restoration of the woman is itself the proclamation of what the kingdom brings.</p>",
    "14": "<p>The synagogue leader&#8217;s indignation reveals the same misreading of the Sabbath that characterized Luke 6&#8217;s Pharisees. His address to the crowd (&#8220;there are six days for work; so come and be healed on those days, not on the Sabbath&#8221;) avoids direct confrontation with Jesus &#8212; addressing the crowd rather than the healer is the strategy of the social coward. The irony: he presides over the house of worship where the Lord of the Sabbath himself has just demonstrated what the Sabbath is for &#8212; the liberation of the oppressed, not the maintenance of religious scheduling.</p>",
    "15": "<p>&#8220;You hypocrites! Doesn&#8217;t each of you on the Sabbath untie your ox or donkey from the stall and lead it out to give it water?&#8221; &#8212; Jesus&#8217;s <em>kal wa-homer</em> argument (lesser to greater): if untying an animal on the Sabbath is acceptable (and universally practiced), how much more releasing a human being from bondage? The animal-untying is a genuine precedent &#8212; Jewish Sabbath law (m. Shabbat 5:1&#8211;4) permitted leading animals to water. The force of the argument is that the leaders&#8217; own practice proves the principle Jesus applies to human healing &#8212; their objection is therefore inconsistent and exposed as hypocritical.</p>",
    "16": "<p>&#8220;Then should not this woman, a daughter of Abraham, whom Satan has kept bound for eighteen long years, be set free on the Sabbath day from what bound her?&#8221; &#8212; the Christological resolution. &#8220;Daughter of Abraham&#8221; (cf. 19:9: &#8220;son of Abraham&#8221; for Zacchaeus) is the covenant title &#8212; she belongs to Israel&#8217;s heritage of promise. Satan&#8217;s binding is the cosmic bondage that Christ came to undo (1 John 3:8: &#8220;the reason the Son of God appeared was to destroy the devil&#8217;s work&#8221;). The Sabbath is precisely the right day for this liberation: the day of divine rest is the day of release from the enemy&#8217;s chains.</p>",
    "17": "<p>&#8220;All his opponents were humiliated, but the people were delighted with all the wonderful things he was doing&#8221; &#8212; the double response mirrors the broader division that Christ&#8217;s ministry creates (12:51: &#8220;division&#8221;). The &#8220;wonderful things&#8221; (<em>endoxois</em>, glorious deeds) the people celebrate echo the language of divine glory &#8212; the crowd witnesses the glory of God in the healings that Jesus performs (John 2:11: &#8220;he revealed his glory, and his disciples believed in him&#8221;). The humiliation of the opponents and the delight of the people is a foretaste of the eschatological reversal (1:52: &#8220;he has brought down rulers from their thrones but has lifted up the humble&#8221;).</p>",
    "18": "<p>&#8220;What is the kingdom of God like? What shall I compare it to?&#8221; &#8212; Jesus&#8217;s double rhetorical question introduces the twin parables of mustard seed and yeast. The kingdom&#8217;s likeness is not self-evident &#8212; it requires parabolic interpretation. The question itself is an invitation: the hearer is drawn into the comparison-making process alongside Jesus. The same invitation underlies all Jesus&#8217;s parabolic teaching: the kingdom defies direct description and can only be approached through analogies that both reveal and conceal, as 8:10 explains (the mysteries of the kingdom are given to the disciples; to others, parables).</p>",
    "19": "<p>&#8220;It is like a mustard seed, which a man took and planted in his garden. It grew and became a tree, and the birds of the air perched in its branches&#8221; &#8212; the mustard seed&#8217;s growth from smallest to largest is the type of the kingdom&#8217;s development from obscure beginning (a carpenter&#8217;s son in Galilee, twelve disciples, a ragged movement) to universal scope. The birds nesting in branches echoes Ezek 17:23 and Dan 4:12 &#8212; the great tree under which the nations find shelter is the image of the Messianic kingdom&#8217;s scope. The Gentiles who come to Christ are the birds nesting in the mustard tree.</p>",
    "20": "<p>&#8220;Again he asked: What shall I compare the kingdom of God to?&#8221; &#8212; the repetition of the question before the second parable emphasizes that both parables are needed to understand the kingdom from two angles. The seed parable emphasizes external growth from small to great; the yeast parable will emphasize internal transformation of a whole substance. Together they describe the kingdom&#8217;s comprehensive effect: outward expansion and inward penetration. Christ who is both the mustard seed buried in the ground (death) and the yeast working through the whole lump (resurrection life) is the embodiment of both parables.</p>",
    "21": "<p>&#8220;It is like yeast that a woman took and mixed into about thirty kilograms of flour until it worked all through the dough&#8221; &#8212; the yeast&#8217;s pervasive, invisible transformation of the flour is a type of the Spirit&#8217;s work in the world through the gospel. Three measures (approximately 36 liters) of flour is the amount Abraham asked Sarah to prepare for the angelic visitors (Gen 18:6) &#8212; a detail that links the kingdom&#8217;s pervasive transformation to the Abrahamic covenant&#8217;s promise of universal blessing (Gen 12:3: &#8220;all peoples on earth will be blessed through you&#8221;). The kingdom works invisibly but completely.</p>",
    "22": "<p>&#8220;Jesus went through the towns and villages, teaching as he made his way to Jerusalem&#8221; &#8212; the travel-narrative summary reminds the reader of the deliberate Christological journey (9:51: &#8220;set his face to go to Jerusalem&#8221;). Every teaching, healing, and parable on the journey is colored by the destination &#8212; the cross is the context of the entire travel section. The geographic movement (towns and villages → Jerusalem) is the narrative shape of the Servant&#8217;s path from proclamation to sacrifice. Luke&#8217;s teaching-while-traveling motif ensures that the passion-journey is also the fullest revelation of the kingdom.</p>",
    "23": "<p>&#8220;Lord, are only a few people going to be saved?&#8221; &#8212; the question about the scope of salvation provokes not a quantitative answer but a demand for personal response. Jewish debates about whether the majority or minority of Israel would be saved (Rabbi Eliezer vs. Rabbi Joshua debates in rabbinic tradition) provide the background. Jesus refuses to answer the census question (how many?) with an eschatological number; instead he redirects to the urgent personal question: are you making every effort to enter? The Christological implication: salvation is not determined by demographic calculation but by response to the one through whom the door is open (John 10:7,9: &#8220;I am the gate&#8221;).</p>",
    "24": "<p>&#8220;Make every effort to enter through the narrow door, because many, I tell you, will try to enter and will not be able to&#8221; &#8212; the narrow door is the exclusive entry into the kingdom. &#8220;Narrow&#8221; (<em>stenēs</em>) does not mean the door is hidden or difficult to find but that it requires a genuine response &#8212; the self cannot bring its comforts, pretensions, or assumptions through. John 10:9 identifies the door explicitly as Jesus himself: &#8220;I am the gate; whoever enters through me will be saved.&#8221; The &#8220;will not be able&#8221; refers not to divine exclusion but to the self-exclusion of those who approach on wrong terms (v.26).</p>",
    "25": "<p>&#8220;Once the owner of the house gets up and closes the door&#8221; &#8212; the closed door is the eschatological point of no return. The parable echoes Noah&#8217;s ark: God shut the door (Gen 7:16: &#8220;then the LORD shut him in&#8221;) and the opportunity for boarding passed. The outside knocking and pleading (&#8220;Sir, open the door for us&#8221;) after the door is closed is the cry of those who assumed inclusion on the basis of proximity rather than relationship. Christ as the door (John 10:9) is also the one who determines when the door closes &#8212; his return is the closing of the door on the present age&#8217;s opportunity.</p>",
    "26": "<p>&#8220;Then you will say: We ate and drank with you, and you taught in our streets&#8221; &#8212; the appeal to historical proximity: we were in the same places, we shared meals, we heard the teaching. The appeal is to external association rather than transformed relationship. The claim is literally true &#8212; the crowds did eat with Jesus (feeding of the 5000; the many dinner scenes of Luke) and hear him teach. But proximity is not the same as faith, and shared meals are not the same as the new covenant blood. The Christological warning: knowing about Jesus is not the same as being known by him.</p>",
    "27": "<p>&#8220;But he will reply: I don&#8217;t know you or where you come from. Away from me, all you evildoers!&#8221; &#8212; the shocking repudiation. &#8220;I don&#8217;t know you&#8221; (<em>ouk oida hymas pothen este</em>, I don&#8217;t know where you are from) denies the relational basis for entry. The citation of Ps 6:8 (&#8220;away from me, all you who do evil&#8221;) frames the rejection as the fulfillment of the psalmist&#8217;s appeal to God against the wicked. Christ as the eschatological judge applies the psalm&#8217;s language to those who claimed proximity without transformation &#8212; the outward association without the inward renewal that the Spirit produces.</p>",
    "28": "<p>&#8220;There will be weeping there, and gnashing of teeth, when you see Abraham, Isaac and Jacob and all the prophets in the kingdom of God, but you yourselves thrown out&#8221; &#8212; the great reversal: the patriarchs and prophets of Israel in the kingdom, while those who claimed their heritage are excluded. The exclusion is not ethnic but covenantal: the patriarchs were people of faith (Heb 11:8&#8211;22) who anticipated the city &#8220;whose architect and builder is God&#8221;; those who merely claimed descent without faith miss what the patriarchs had. Christ as the seed of Abraham (Gal 3:16: &#8220;the promises were spoken to Abraham and to his seed, meaning one person, who is Christ&#8221;) is the only ground for inheriting what the patriarchs anticipated.</p>",
    "29": "<p>&#8220;People will come from east and west and north and south, and will take their places at the feast in the kingdom of God&#8221; &#8212; the fulfillment of the Abrahamic promise (Gen 12:3: &#8220;all peoples on earth will be blessed through you&#8221;) and the Isaianic ingathering (Isa 49:12: &#8220;some from the north, some from the west, some from the region of Aswan&#8221;; 43:5&#8211;6). The universal feast in the kingdom is the eschatological Messianic banquet (Isa 25:6&#8211;8: &#8220;the LORD Almighty will prepare a feast of rich food for all peoples&#8221;). Christ as the host of the feast (the Bridegroom of Rev 19:9: &#8220;blessed are those who are invited to the wedding supper of the Lamb&#8221;) gathers the nations.</p>",
    "30": "<p>&#8220;Indeed there are those who are last who will be first, and first who will be last&#8221; &#8212; the great reversal principle that recurs throughout Luke (1:52&#8211;53: Magnificat; 6:20&#8211;26: Beatitudes/Woes; 16:19&#8211;31: Rich man and Lazarus; 18:14: justified vs. not justified). The reversal is the shape of the kingdom&#8217;s justice &#8212; and it is grounded in the reversal enacted in the cross and resurrection: Christ who was last (crucified with criminals, outside the city gate) is now first (exalted above all names, Phil 2:9&#8211;11). The pattern of Christ&#8217;s self-humiliation and exaltation is the pattern that all kingdom-reversals follow.</p>",
    "31": "<p>The Pharisees&#8217; warning that Herod wants to kill Jesus is ambiguous &#8212; whether sincere concern or an attempt to divert Jesus from Jerusalem, it functions as a test of his resolve. Herod (Antipas) had already killed John the Baptist (9:9) and was curious about Jesus (9:7&#8211;9). The warning parallels the satanic temptation (4:1&#8211;13) in that it offers an alternative to the cross-path &#8212; diversion through fear. Jesus&#8217;s response demonstrates the resolve of the Servant (Isa 50:7: &#8220;I have set my face like flint&#8221;) who is not deterred by political threats from the path the Father has set.</p>",
    "32": "<p>&#8220;Go tell that fox, I will keep on driving out demons and healing people today and tomorrow, and on the third day I will reach my goal&#8221; &#8212; the &#8220;today/tomorrow/third day&#8221; structure is a Christological pointer. The third day is resurrection language &#8212; the same &#8220;third day&#8221; of Hos 6:2 (&#8220;after two days he will revive us; on the third day he will restore us, that we may live in his presence&#8221;) and the passion predictions (9:22; 18:33). Jesus describes his ministry and his destination in terms that encode his death and resurrection: the work of healing and exorcism continues until it is completed in the cross, whose completion is the resurrection on the third day.</p>",
    "33": "<p>&#8220;In any case, I must press on today and tomorrow and the next day &#8212; for surely no prophet can die outside Jerusalem!&#8221; &#8212; the <em>dei</em> (it is necessary) of divine compulsion appears again (4:43; 9:22; 17:25; 22:37; 24:7,26,44). The irony of the statement: Jerusalem, which should have welcomed the prophets, has a history of killing them (v.34). Christ&#8217;s necessity to die in Jerusalem is the fulfillment of this prophetic pattern &#8212; and its reversal: the prophet who dies in Jerusalem will rise from there, making the city of death the city of resurrection and the origin of the worldwide proclamation.</p>",
    "34": "<p>&#8220;Jerusalem, Jerusalem, you who kill the prophets and stone those sent to you, how often I have longed to gather your children together, as a hen gathers her chicks under her wings, and you were not willing!&#8221; &#8212; the Jerusalem lament is one of the most tender Christological statements in Luke. The longing of Christ to gather Israel echoes the language of YHWH&#8217;s maternal love: Isa 31:5 (&#8220;like birds hovering overhead, the LORD Almighty will shield Jerusalem; he will shield it and deliver it&#8221;); Deut 32:11 (&#8220;like an eagle that stirs up its nest and hovers over its young&#8221;; Ps 91:4). The Christ who wept over Jerusalem (19:41) is the incarnation of this divine longing. The &#8220;you were not willing&#8221; is the sorrow of refused grace.</p>",
    "35": "<p>&#8220;Look, your house is left to you desolate. I tell you, you will not see me again until you say, &#8216;Blessed is he who comes in the name of the Lord&#8217;&#8221; &#8212; the desolation of the house (the Temple) is Jer 22:5 (&#8220;this palace will become a ruin&#8221;) and Ezek 10&#8211;11 (the glory departing from the Temple). The quoted Ps 118:26 (&#8220;Blessed is he who comes in the name of the Lord&#8221;) is the Palm Sunday cry (19:38) and the eschatological acclamation &#8212; both at the triumphal entry and at the parousia. The verse holds together the judgment on Jerusalem&#8217;s rejection and the hope of final recognition: the city that rejects Christ now will acknowledge him at last.</p>"
  }
}

def main():
    existing = load_comm('mkt-christ', 'luke')
    merge_comm(existing, DATA)
    merge_comm(existing, FILL_CH12)
    merge_comm(existing, FILL_CH13)
    save_comm('mkt-christ', 'luke', existing)
    total = sum(len(v) for v in existing.values())
    print(f"Luke mkt-christ: {len(existing)} chapters, {total} verses written.")

if __name__ == '__main__':
    main()
